<?php
declare(strict_types=1);
require __DIR__ . '/_bootstrap.php'; admin_require_login();
if(is_post()){
 verify_csrf();$id=(int)($_POST['id'] ?? 0);$action=(string)($_POST['action'] ?? '');$status=match($action){'publish'=>'published','reject'=>'rejected','trash'=>'trash','restore'=>'pending',default=>'pending'};$st=db()->prepare('UPDATE notes SET status=?,published_at=CASE WHEN ?=\'published\' THEN CURRENT_TIMESTAMP ELSE published_at END WHERE id=?');$st->execute([$status,$status,$id]);flash('success','Not durumu güncellendi.');redirect('notes.php?status='.rawurlencode((string)($_GET['status']??'pending')));
}
$status=(string)($_GET['status'] ?? 'pending');$st=db()->prepare('SELECT * FROM notes WHERE status=? ORDER BY created_at DESC');$st->execute([$status]);$notes=$st->fetchAll();admin_head('Kenar notları'); ?>
<div class="page-head"><div><p class="eyebrow">MODERASYON</p><h1>Kenar notları</h1></div></div><div class="tabs"><?php foreach(['pending'=>'Bekleyen','published'=>'Yayımlanan','rejected'=>'Reddedilen','trash'=>'Çöp'] as $k=>$v): ?><a class="<?= $status===$k?'active':'' ?>" href="?status=<?= $k ?>"><?= $v ?></a><?php endforeach; ?></div><div class="list"><?php foreach($notes as $n): ?><article class="panel"><p><?= e($n['message']) ?></p><small><?= e($n['name']) ?> · <?= e($n['created_at']) ?></small><form method="post" class="form-actions"><?= csrf_field() ?><input type="hidden" name="id" value="<?= (int)$n['id'] ?>"><?php if($status!=='published'): ?><button name="action" value="publish">Yayımla</button><?php endif; ?><?php if($status!=='rejected'): ?><button class="secondary" name="action" value="reject">Reddet</button><?php endif; ?><button class="danger" name="action" value="trash">Çöpe taşı</button></form></article><?php endforeach; ?></div><?php if(!$notes): ?><div class="empty">Bu bölümde not yok.</div><?php endif; ?><?php admin_foot(); ?>
